/**
 * Neo Brutalism Gaming Design Tokens
 *
 * Complete design token system for the Perfect World Neo Brutalism Gaming visual identity.
 * Defines colors, borders, shadows, typography, spacing, and layout breakpoints.
 *
 * @see Requirements 1.1, 1.2, 1.3, 1.4, 1.5, 1.6, 1.7, 2.1-2.7, 3.1-3.7, 4.1-4.7, 11.1-11.8
 */

/**
 * Color Palette Interface
 * Defines the structure for dark and light mode color schemes
 */
export interface ColorPalette {
  background: string;
  panel: string;
  border: string;
  textPrimary: string;
  textSecondary: string;
  accentCyan: string;
  accentPurple: string;
  accentGold: string;
  accentCrimson: string;
}

/**
 * Neo Brutalism Gaming Design Token System
 * Single source of truth for all design values
 */
export const neoBrutalism = {
  /**
   * Color Palettes
   * Requirement 1.1, 2.1-2.7
   */
  colors: {
    dark: {
      background: '#0A0A0A',
      panel: '#141414',
      border: '#2B2B2B',
      textPrimary: '#FFFFFF',
      textSecondary: '#B0B0B0',
      accentCyan: '#00E5FF',      // Primary accent for CTAs, links, highlights
      accentPurple: '#9B5CFF',    // Secondary accent for badges, tags
      accentGold: '#FFD54A',      // Tertiary accent for premium features
      accentCrimson: '#FF4D6D',   // Error/warning states
    } as ColorPalette,
    light: {
      background: '#F6F6F6',
      panel: '#FFFFFF',
      border: '#000000',
      textPrimary: '#111111',
      textSecondary: '#555555',
      accentCyan: '#009DFF',
      accentPurple: '#6C3DFF',
      accentGold: '#E5A500',
      accentCrimson: '#FF4D6D',
    } as ColorPalette,
  },

  /**
   * Border Configurations
   * Requirement 1.2, 4.1-4.2
   * 3px default, 4px heavy, solid black
   */
  borders: {
    width: {
      default: '3px',   // Default for cards, buttons, inputs, panels
      thick: '3px',     // Alias for default (backward compatibility)
      heavy: '4px',     // Heavy for hero elements and primary CTAs
    },
    style: 'solid',
    color: {
      dark: '#2B2B2B',
      light: '#000000',
    },
    radius: {
      none: '0px',      // Default Neo-Brutalism aesthetic
      subtle: '4px',    // Optional subtle rounding for badges
    },
  },

  /**
   * Shadow Configurations
   * Requirement 1.3, 4.3-4.7
   * 4px, 6px, 8px offsets with colored shadows
   */
  shadows: {
    offset: {
      sm: '4px 4px',    // Small offset for subtle depth
      md: '6px 6px',    // Medium offset for cards and secondary elements
      lg: '8px 8px',    // Large offset for featured content and premium elements
      xl: '8px 8px',    // Extra large (alias for lg, for backward compatibility)
    },
    color: {
      // Backward compatibility - mode-based colors
      dark: 'rgba(0, 0, 0, 0.8)',
      light: 'rgba(0, 0, 0, 1)',
      // New colored shadow options
      cyan: 'rgba(0, 229, 255, 0.4)',       // Primary buttons, active elements
      purple: 'rgba(155, 92, 255, 0.4)',    // Cards, secondary elements
      gold: 'rgba(255, 213, 74, 0.4)',      // Featured content, premium elements
      black: 'rgba(0, 0, 0, 1)',            // Default shadow
    },
    // Pre-composed shadow values for convenience
    presets: {
      cyanSm: '4px 4px 0px rgba(0, 229, 255, 0.4)',
      cyanMd: '6px 6px 0px rgba(0, 229, 255, 0.4)',
      cyanLg: '8px 8px 0px rgba(0, 229, 255, 0.4)',
      purpleSm: '4px 4px 0px rgba(155, 92, 255, 0.4)',
      purpleMd: '6px 6px 0px rgba(155, 92, 255, 0.4)',
      purpleLg: '8px 8px 0px rgba(155, 92, 255, 0.4)',
      goldSm: '4px 4px 0px rgba(255, 213, 74, 0.4)',
      goldMd: '6px 6px 0px rgba(255, 213, 74, 0.4)',
      goldLg: '8px 8px 0px rgba(255, 213, 74, 0.4)',
      blackSm: '4px 4px 0px rgba(0, 0, 0, 1)',
      blackMd: '6px 6px 0px rgba(0, 0, 0, 1)',
      blackLg: '8px 8px 0px rgba(0, 0, 0, 1)',
    },
  },

  /**
   * Typography Scales
   * Requirement 1.4, 3.1-3.7
   * Anton for headings, Inter for body
   */
  typography: {
    fontFamily: {
      heading: "'Anton', 'Arial Black', sans-serif",
      body: "'Inter', 'Arial', sans-serif",
    },
    hero: {
      family: "'Anton', 'Arial Black', sans-serif",
      desktop: '72px',
      mobile: '36px',
      weight: 400,
      lineHeight: 1.0,
      letterSpacing: '0.02em',
    },
    heading: {
      family: "'Anton', 'Arial Black', sans-serif",
      desktop: '48px',
