    body: {
      family: "'Inter', 'Arial', sans-serif",
      size: '16px',
      sizeLarge: '18px',
      weight: 400,
      weightBold: 700,
      lineHeight: '1.5',
      letterSpacing: '0em',
    },
    button: {
      size: '14px',
      weight: 700,
      letterSpacing: '0.1em',
      textTransform: 'uppercase' as const,
    },
    label: {
      size: '12px',
      weight: 600,
      letterSpacing: '0.05em',
      textTransform: 'uppercase' as const,
    },
  },

  /**
   * Spacing Scale
   * Requirement 1.5, 11.1-11.8
   * 8px base unit
   */
  spacing: {
    xs: '8px',      // 8px - tight spacing
    sm: '16px',     // 16px - small spacing
    md: '24px',     // 24px - medium spacing, card gaps
    lg: '32px',     // 32px - large spacing, mobile sections
    xl: '48px',     // 48px - extra large spacing, desktop sections
    xxl: '64px',    // 64px - extra extra large spacing
  },

  /**
   * Layout Breakpoints
   * Requirement 1.7, 11.8
   */
  layout: {
    breakpoints: {
      sm: '768px',    // Tablet
      md: '1024px',   // Desktop
      lg: '1440px',   // Large desktop
      xl: '2560px',   // Ultra-wide
    },
    maxWidth: '1440px',   // Max content width
    minWidth: '320px',    // Minimum supported viewport
    containerPadding: {
      mobile: '24px',     // Horizontal padding on mobile
      desktop: '48px',    // Horizontal padding on desktop
    },
  },

  /**
   * Animation Timings
   * Requirement 12.1-12.8
   */
  animation: {
    duration: {
      fast: '100ms',      // Click/press animations
      normal: '200ms',    // Hover transitions
      slow: '300ms',      // Complex transitions
    },
    easing: {
      easeOut: 'ease-out',
      easeIn: 'ease-in',
      easeInOut: 'ease-in-out',
    },
  },

  /**
   * Z-Index Scale
   * For layering components
   */
  zIndex: {
    base: 0,
    dropdown: 1000,
    sticky: 1100,
    modal: 1200,
    popover: 1300,
    tooltip: 1400,
  },
} as const;

/**
 * Type exports for TypeScript support
 */
export type NeoBrutalismTokens = typeof neoBrutalism;
export type ColorMode = 'dark' | 'light';
export type ShadowColor = 'cyan' | 'purple' | 'gold' | 'black';
export type ShadowSize = 'sm' | 'md' | 'lg';
export type SpacingSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'xxl';
export type Breakpoint = 'sm' | 'md' | 'lg' | 'xl';

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  /* Light mode (default) */
  :root,
  [data-theme='light'] {
    /* Colors - Requirement 2.1-2.7 */
    --color-background: #F6F6F6;
    --color-panel: #FFFFFF;
    --color-border: #000000;
    --color-text-primary: #111111;
    --color-text-secondary: #555555;
    --color-accent-cyan: #009DFF;
    --color-accent-purple: #6C3DFF;
    --color-accent-gold: #E5A500;
    --color-accent-crimson: #FF4D6D;

    /* Borders - Requirement 1.2, 4.1-4.2 */
    --border-width-default: 3px;
    --border-width-heavy: 4px;
    --border-radius-none: 0px;
    --border-radius-subtle: 4px;

    /* Shadows - Requirement 1.3, 4.3-4.7 */
    --shadow-offset-sm: 4px;
    --shadow-offset-md: 6px;
    --shadow-offset-lg: 8px;
    --shadow-color-cyan: rgba(0, 157, 255, 0.4);
    --shadow-color-purple: rgba(108, 61, 255, 0.4);
    --shadow-color-gold: rgba(229, 165, 0, 0.4);
    --shadow-color-black: rgba(0, 0, 0, 1);

    /* Spacing - Requirement 1.5, 11.1-11.8 */
    --spacing-xs: 8px;
    --spacing-sm: 16px;
    --spacing-md: 24px;
    --spacing-lg: 32px;
    --spacing-xl: 48px;
    --spacing-xxl: 64px;

    /* Typography - Requirement 1.4, 3.1-3.7 */
    --font-heading: 'Anton', 'Arial Black', sans-serif;
    --font-body: 'Inter', 'Arial', sans-serif;
    --font-size-hero-desktop: 72px;
    --font-size-hero-mobile: 36px;
    --font-size-heading-desktop: 48px;
    --font-size-heading-mobile: 32px;
    --font-size-subheading: 24px;
    --font-size-body: 16px;
    --font-size-body-large: 18px;
    --font-size-button: 14px;
    --font-size-label: 12px;

    /* Animation - Requirement 12.1-12.8 */
    --animation-duration-fast: 100ms;
    --animation-duration-normal: 200ms;
    --animation-duration-slow: 300ms;
  }

  /* Dark mode */
  [data-theme='dark'] {
    /* Colors - Requirement 2.1-2.7 */
    --color-background: #0A0A0A;
    --color-panel: #141414;
    --color-border: #2B2B2B;
    --color-text-primary: #FFFFFF;
    --color-text-secondary: #B0B0B0;
    --color-accent-cyan: #00E5FF;
    --color-accent-purple: #9B5CFF;
    --color-accent-gold: #FFD54A;
    --color-accent-crimson: #FF4D6D;

    /* Shadows - adjusted for dark mode */
    --shadow-color-cyan: rgba(0, 229, 255, 0.4);
    --shadow-color-purple: rgba(155, 92, 255, 0.4);
    --shadow-color-gold: rgba(255, 213, 74, 0.4);
    --shadow-color-black: rgba(0, 0, 0, 0.8);
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    background-color: var(--color-background);
    color: var(--color-text-primary);
    font-family: 'Inter', sans-serif;
    font-size: 16px;
    line-height: 1.5;
    min-width: 320px;
    overflow-x: hidden;
  }

  /* Anton font for headings */
  h1, h2, h3 {
    font-family: 'Anton', sans-serif;
  }

  /* Better defaults for Neo Brutalism */
  * {
    border-color: var(--color-border);
  }

  ::selection {
    background: #FFE066;
    color: #000;
  }
}

@layer utilities {
  /* ===== BORDER UTILITIES ===== */
  /* Requirement 1.2, 4.1-4.2 */
  
  .neo-border {
    border: var(--border-width-default) solid var(--color-border);
  }

  .neo-border-heavy {
    border: var(--border-width-heavy) solid var(--color-border);
  }

  .neo-border-top {
    border-top: var(--border-width-default) solid var(--color-border);
  }

  .neo-border-bottom {
    border-bottom: var(--border-width-default) solid var(--color-border);
  }

  .neo-border-left {
    border-left: var(--border-width-default) solid var(--color-border);
  }

  .neo-border-right {
    border-right: var(--border-width-default) solid var(--color-border);
  }

  /* Border radius utilities */
  .neo-radius-none {
    border-radius: var(--border-radius-none);
  }

  .neo-radius-subtle {
    border-radius: var(--border-radius-subtle);
  }

  /* ===== SHADOW UTILITIES ===== */
  /* Requirement 1.3, 4.3-4.7 */
  
  /* Cyan shadows - primary buttons, active elements */
  .neo-shadow-cyan-sm {
    box-shadow: var(--shadow-offset-sm) var(--shadow-offset-sm) 0px var(--shadow-color-cyan);
  }

  .neo-shadow-cyan-md {
    box-shadow: var(--shadow-offset-md) var(--shadow-offset-md) 0px var(--shadow-color-cyan);
  }

  .neo-shadow-cyan-lg {
    box-shadow: var(--shadow-offset-lg) var(--shadow-offset-lg) 0px var(--shadow-color-cyan);
  }

  /* Purple shadows - cards, secondary elements */
  .neo-shadow-purple-sm {
    box-shadow: var(--shadow-offset-sm) var(--shadow-offset-sm) 0px var(--shadow-color-purple);
  }

  .neo-shadow-purple-md {
    box-shadow: var(--shadow-offset-md) var(--shadow-offset-md) 0px var(--shadow-color-purple);
  }

  .neo-shadow-purple-lg {
    box-shadow: var(--shadow-offset-lg) var(--shadow-offset-lg) 0px var(--shadow-color-purple);
  }

  /* Gold shadows - featured content, premium elements */
  .neo-shadow-gold-sm {
    box-shadow: var(--shadow-offset-sm) var(--shadow-offset-sm) 0px var(--shadow-color-gold);
  }

  .neo-shadow-gold-md {
    box-shadow: var(--shadow-offset-md) var(--shadow-offset-md) 0px var(--shadow-color-gold);
  }

  .neo-shadow-gold-lg {
    box-shadow: var(--shadow-offset-lg) var(--shadow-offset-lg) 0px var(--shadow-color-gold);
  }

  /* Black shadows - default */
  .neo-shadow-black-sm {
    box-shadow: var(--shadow-offset-sm) var(--shadow-offset-sm) 0px var(--shadow-color-black);
  }

  .neo-shadow-black-md {
    box-shadow: var(--shadow-offset-md) var(--shadow-offset-md) 0px var(--shadow-color-black);
  }

  .neo-shadow-black-lg {
    box-shadow: var(--shadow-offset-lg) var(--shadow-offset-lg) 0px var(--shadow-color-black);
  }

  /* ===== SPACING UTILITIES ===== */
  /* Requirement 1.5, 11.1-11.8 */
  
  .neo-gap-xs { gap: var(--spacing-xs); }
  .neo-gap-sm { gap: var(--spacing-sm); }
  .neo-gap-md { gap: var(--spacing-md); }
  .neo-gap-lg { gap: var(--spacing-lg); }
  .neo-gap-xl { gap: var(--spacing-xl); }
  .neo-gap-xxl { gap: var(--spacing-xxl); }

  .neo-p-xs { padding: var(--spacing-xs); }
  .neo-p-sm { padding: var(--spacing-sm); }
  .neo-p-md { padding: var(--spacing-md); }
  .neo-p-lg { padding: var(--spacing-lg); }
  .neo-p-xl { padding: var(--spacing-xl); }
  .neo-p-xxl { padding: var(--spacing-xxl); }

  .neo-m-xs { margin: var(--spacing-xs); }
  .neo-m-sm { margin: var(--spacing-sm); }
  .neo-m-md { margin: var(--spacing-md); }
  .neo-m-lg { margin: var(--spacing-lg); }
  .neo-m-xl { margin: var(--spacing-xl); }
  .neo-m-xxl { margin: var(--spacing-xxl); }

  /* ===== ROTATION UTILITIES ===== */
  /* Requirement 4.8, 8.6 - Playful asymmetry */
  
  .neo-rotate-1 { transform: rotate(1deg); }
  .neo-rotate-2 { transform: rotate(2deg); }
  .neo-rotate-neg1 { transform: rotate(-1deg); }
  .neo-rotate-neg2 { transform: rotate(-2deg); }

  /* ===== HOVER EFFECTS ===== */
  /* Requirement 4.6, 9.5, 10.4, 12.1-12.4 */
  
  /* Standard hover - reduces shadow offset */
  .neo-hover {
    transition: transform var(--animation-duration-normal) ease-out, 
                box-shadow var(--animation-duration-normal) ease-out;
  }
  .neo-hover:hover {
    transform: translate(3px, 3px);
  }

  /* Hover with cyan glow - for interactive cards */
  .neo-hover-glow-cyan {
    transition: transform var(--animation-duration-normal) ease-out,
                box-shadow var(--animation-duration-normal) ease-out,
                outline var(--animation-duration-normal) ease-out;
  }
  .neo-hover-glow-cyan:hover {
    transform: scale(1.03);
    outline: 2px solid var(--color-accent-cyan);
    outline-offset: 0px;
    box-shadow: 0 0 20px var(--shadow-color-cyan);
  }

  /* Hover with purple glow */
  .neo-hover-glow-purple {
    transition: transform var(--animation-duration-normal) ease-out,
                box-shadow var(--animation-duration-normal) ease-out,
                outline var(--animation-duration-normal) ease-out;
  }
  .neo-hover-glow-purple:hover {
    transform: scale(1.03);
    outline: 2px solid var(--color-accent-purple);
    outline-offset: 0px;
    box-shadow: 0 0 20px var(--shadow-color-purple);
  }

  /* Hover with gold glow */
  .neo-hover-glow-gold {
    transition: transform var(--animation-duration-normal) ease-out,
                box-shadow var(--animation-duration-normal) ease-out,
                outline var(--animation-duration-normal) ease-out;
  }
  .neo-hover-glow-gold:hover {
    transform: scale(1.03);
    outline: 2px solid var(--color-accent-gold);
    outline-offset: 0px;
    box-shadow: 0 0 20px var(--shadow-color-gold);
  }

  /* Lift hover - opposite direction */
  .neo-lift {
    transition: transform var(--animation-duration-normal) ease-out, 
                box-shadow var(--animation-duration-normal) ease-out;
  }
  .neo-lift:hover {
    transform: translateY(-8px);
    box-shadow: var(--shadow-offset-lg) calc(var(--shadow-offset-lg) + 4px) 0px var(--color-border);
  }

  /* ===== BUTTON UTILITIES ===== */
  /* Requirement 9.1-9.8 */
  
  .neo-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 16px 32px;
    border: var(--border-width-heavy) solid var(--color-border);
    font-family: var(--font-heading);
    font-size: var(--font-size-button);
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-weight: 700;
    box-shadow: var(--shadow-offset-md) var(--shadow-offset-md) 0px var(--shadow-color-cyan);
    transition: transform var(--animation-duration-fast) ease-in, 
                box-shadow var(--animation-duration-fast) ease-in;
    cursor: pointer;
    border-radius: var(--border-radius-none);
  }
  .neo-btn:hover {
    transform: translate(3px, 3px);
    box-shadow: calc(var(--shadow-offset-md) - 3px) calc(var(--shadow-offset-md) - 3px) 0px var(--shadow-color-cyan);
  }
  .neo-btn:active {
    transform: translate(6px, 6px);
    box-shadow: none;
  }
  .neo-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    pointer-events: none;
  }

  /* ===== CARD UTILITIES ===== */
  /* Requirement 10.1-10.8 */
  
  .neo-card {
    border: var(--border-width-default) solid var(--color-border);
    border-radius: var(--border-radius-none);
    background: var(--color-panel);
  }

  .neo-card-interactive {
    transition: transform var(--animation-duration-normal) ease-out,
                box-shadow var(--animation-duration-normal) ease-out;
    cursor: pointer;
  }

  /* ===== BACKGROUND PATTERNS ===== */
  
  .bg-dots {
    background-image: radial-gradient(circle, var(--color-border) 1px, transparent 1px);
    background-size: 20px 20px;
  }

  .bg-grid {
    background-image: 
      linear-gradient(var(--color-border) 1px, transparent 1px),
      linear-gradient(90deg, var(--color-border) 1px, transparent 1px);
    background-size: 40px 40px;
    background-position: -1px -1px;
  }

  .bg-stripes {
    background-image: repeating-linear-gradient(
      45deg,
      transparent,
      transparent 10px,
      rgba(0,0,0,0.03) 10px,
      rgba(0,0,0,0.03) 20px
    );
  }

  /* ===== BADGE/STICKER UTILITIES ===== */
  
  .neo-sticker {
    display: inline-block;
    padding: 4px 12px;
    border: var(--border-width-default) solid var(--color-border);
    border-radius: 999px;
    font-weight: 800;
    font-size: var(--font-size-label);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    transform: rotate(-2deg);
  }

  .neo-badge {
    display: inline-block;
    padding: 4px 12px;
    border: var(--border-width-default) solid var(--color-border);
    border-radius: var(--border-radius-subtle);
    font-weight: 700;
    font-size: var(--font-size-label);
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  /* ===== ANIMATION UTILITIES ===== */
  /* Requirement 12.5-12.8 */
  
  .neo-float {
    animation: neo-float 3s ease-in-out infinite;
  }

  .neo-bounce {
    animation: neo-bounce 2s ease-in-out infinite;
  }

  .neo-wiggle {
    animation: neo-wiggle 0.5s ease-in-out;
  }

  /* ===== ACCESSIBILITY ===== */
  /* Requirement 14.2 */
  
  .neo-focus-visible:focus-visible {
    outline: 2px solid var(--color-accent-cyan);
    outline-offset: 2px;
  }

  /* Respect reduced motion preference - Requirement 14.8 */
  @media (prefers-reduced-motion: reduce) {
    .neo-hover,
    .neo-hover-glow-cyan,
    .neo-hover-glow-purple,
    .neo-hover-glow-gold,
    .neo-lift,
    .neo-btn,
    .neo-card-interactive,
    .neo-float,
    .neo-bounce,
    .neo-wiggle {
      animation: none !important;
      transition: none !important;
    }
  }
}

@layer base {
  @keyframes neo-float {
    0%, 100% { transform: translateY(0px); }
    50% { transform: translateY(-10px); }
  }

  @keyframes neo-bounce {
    0%, 100% { transform: translateY(0px) scale(1); }
    50% { transform: translateY(-5px) scale(1.02); }
  }

  @keyframes neo-wiggle {
    0%, 100% { transform: rotate(0deg); }
    25% { transform: rotate(-2deg); }
    75% { transform: rotate(2deg); }
  }

  @keyframes spin-slow {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
  }

  .animate-spin-slow {
    animation: spin-slow 20s linear infinite;
  }
}

