'use client';

import React, { forwardRef, useState } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type ButtonVariant = 'primary' | 'secondary' | 'tertiary';
export type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Visual variant */
  variant?: ButtonVariant;
  /** Size preset */
  size?: ButtonSize;
  /** Full width button */
  fullWidth?: boolean;
  /** Loading state */
  loading?: boolean;
}

const sizeStyles: Record<ButtonSize, React.CSSProperties> = {
  sm: { padding: '8px 16px' },
  md: { padding: '12px 24px' },
  lg: { padding: '16px 32px' },
};

/**
 * Button component with Neo Brutalism Gaming styling.
 *
 * - Primary: Cyan background, 4px black border, 6px cyan shadow
 * - Secondary: Transparent background, 3px cyan border, 4px cyan shadow
 * - Tertiary: Purple background, 3px black border, 4px purple shadow
 *
 * Supports hover effects (translate 3px down-right, reduce shadow by 3px),
 * pressed effects (translate 6px down-right, remove shadow),
 * and focus indicators (2px cyan outline with 2px offset).
 *
 * @see Requirements 9.1, 9.2, 9.3, 9.4, 9.5, 9.6, 9.7, 9.8
 */
export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      variant = 'primary',
      size = 'md',
      fullWidth = false,
      loading = false,
      disabled,
      style,
      children,
      onMouseDown,
      onMouseUp,
      onMouseLeave,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const [isPressed, setIsPressed] = useState(false);
    const [isHovered, setIsHovered] = useState(false);

    const baseStyles: React.CSSProperties = {
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: neoBrutalism.typography.button.size,
      fontWeight: neoBrutalism.typography.button.weight,
      letterSpacing: neoBrutalism.typography.button.letterSpacing,
      textTransform: neoBrutalism.typography.button.textTransform,
      cursor: disabled || loading ? 'not-allowed' : 'pointer',
      transition: 'transform 200ms ease-out, box-shadow 200ms ease-out',
      opacity: disabled ? 0.5 : 1,
      width: fullWidth ? '100%' : undefined,
      borderRadius: neoBrutalism.borders.radius.none,
      position: 'relative',
      ...sizeStyles[size],
    };

    const variantStyles: Record<ButtonVariant, React.CSSProperties> = {
      primary: {
        backgroundColor: colors.accentCyan,
        color: mode === 'dark' ? '#0A0A0A' : '#FFFFFF',
        border: `${neoBrutalism.borders.width.heavy} solid ${mode === 'dark' ? '#000000' : colors.border}`,
        boxShadow: neoBrutalism.shadows.presets.cyanMd,
      },
      secondary: {
        backgroundColor: 'transparent',
        color: colors.accentCyan,
        border: `${neoBrutalism.borders.width.default} solid ${colors.accentCyan}`,
        boxShadow: neoBrutalism.shadows.presets.cyanSm,
      },
      tertiary: {
        backgroundColor: colors.accentPurple,
        color: '#FFFFFF',
        border: `${neoBrutalism.borders.width.default} solid ${mode === 'dark' ? '#000000' : colors.border}`,
        boxShadow: neoBrutalism.shadows.presets.purpleSm,
      },
    };

    // Hover effect: translate 3px down-right, reduce shadow by 3px
    const hoverTransform = isHovered && !disabled && !loading && !isPressed
      ? 'translate(3px, 3px)'
      : 'translate(0, 0)';

    // Pressed effect: translate 6px down-right, remove shadow
    const pressedTransform = isPressed && !disabled && !loading
      ? 'translate(6px, 6px)'
      : hoverTransform;

    // Shadow adjustments for hover and pressed states
    let boxShadow = variantStyles[variant].boxShadow;
    if (isPressed && !disabled && !loading) {
      boxShadow = 'none';
    } else if (isHovered && !disabled && !loading) {
      // Reduce shadow offset by 3px for hover
      if (variant === 'primary') {
        boxShadow = '3px 3px 0px rgba(0, 229, 255, 0.4)';
      } else if (variant === 'secondary') {
        boxShadow = '1px 1px 0px rgba(0, 229, 255, 0.4)';
      } else if (variant === 'tertiary') {
        boxShadow = '1px 1px 0px rgba(155, 92, 255, 0.4)';
      }
    }

    const combinedStyle: React.CSSProperties = {
      ...baseStyles,
      ...variantStyles[variant],
      transform: pressedTransform,
      boxShadow,
      ...style,
    };

    // Focus indicator styles
    const focusStyles: React.CSSProperties = {
      outline: `2px solid ${colors.accentCyan}`,
      outlineOffset: '2px',
    };

    const handleMouseDown = (e: React.MouseEvent<HTMLButtonElement>) => {
      if (!disabled && !loading) {
        setIsPressed(true);
      }
      onMouseDown?.(e);
    };

    const handleMouseUp = (e: React.MouseEvent<HTMLButtonElement>) => {
      setIsPressed(false);
      onMouseUp?.(e);
    };

    const handleMouseLeave = (e: React.MouseEvent<HTMLButtonElement>) => {
      setIsPressed(false);
      setIsHovered(false);
      onMouseLeave?.(e);
    };

    return (
      <button
        ref={ref}
        disabled={disabled || loading}
        style={combinedStyle}
        aria-busy={loading || undefined}
        onMouseEnter={() => !disabled && !loading && setIsHovered(true)}
        onMouseLeave={handleMouseLeave}
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        onFocus={(e) => {
          Object.assign(e.currentTarget.style, focusStyles);
        }}
        onBlur={(e) => {
          e.currentTarget.style.outline = '';
          e.currentTarget.style.outlineOffset = '';
        }}
        {...props}
      >
        {loading && (
          <span
            aria-hidden="true"
            style={{
              width: '16px',
              height: '16px',
              border: '2px solid currentColor',
              borderTopColor: 'transparent',
              borderRadius: '50%',
              animation: 'spin 0.6s linear infinite',
            }}
          />
        )}
        {children}
      </button>
    );
  }
);

Button.displayName = 'Button';

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import React from 'react';
import { render, fireEvent, cleanup } from '@testing-library/react';
import { Button } from './Button';
import { ThemeProvider } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

// Mock localStorage
const localStorageMock = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: vi.fn((key: string) => store[key] ?? null),
    setItem: vi.fn((key: string, value: string) => {
      store[key] = value;
    }),
    removeItem: vi.fn((key: string) => {
      delete store[key];
    }),
    clear: vi.fn(() => {
      store = {};
    }),
    get length() {
      return Object.keys(store).length;
    },
    key: vi.fn((index: number) => Object.keys(store)[index] ?? null),
  };
})();

Object.defineProperty(window, 'localStorage', { value: localStorageMock });

function wrapper({ children }: { children: React.ReactNode }) {
  return <ThemeProvider>{children}</ThemeProvider>;
}

describe('Button Component', () => {
  beforeEach(() => {
    localStorageMock.clear();
    vi.clearAllMocks();
  });

  afterEach(() => {
    cleanup();
  });

  describe('Variant Rendering - Requirement 9.1, 9.2, 9.3', () => {
    it('renders primary variant with cyan background and 4px black border', () => {
      const { getByRole } = render(
        <Button variant="primary">Click Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.backgroundColor).toBe('rgb(0, 229, 255)');
      expect(button.style.border).toContain('4px');
      expect(button.style.border).toContain('solid');
      expect(button.style.boxShadow).toContain('6px 6px');
      expect(button.style.boxShadow).toContain('0, 229, 255');
    });

    it('renders secondary variant with transparent background and 3px cyan border', () => {
      const { getByRole } = render(
        <Button variant="secondary">Click Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.backgroundColor).toBe('transparent');
      expect(button.style.color).toBe('rgb(0, 229, 255)');
      expect(button.style.border).toContain('3px');
      expect(button.style.border).toContain('solid');
      expect(button.style.boxShadow).toContain('4px 4px');
      expect(button.style.boxShadow).toContain('0, 229, 255');
    });

    it('renders tertiary variant with purple background and 3px black border', () => {
      const { getByRole } = render(
        <Button variant="tertiary">Click Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.backgroundColor).toBe('rgb(155, 92, 255)');
      expect(button.style.color).toBe('rgb(255, 255, 255)');
      expect(button.style.border).toContain('3px');
      expect(button.style.border).toContain('solid');
      expect(button.style.boxShadow).toContain('4px 4px');
      expect(button.style.boxShadow).toContain('155, 92, 255');
    });
  });

  describe('Size Variants - Requirement 9.4', () => {
    it('renders small size with correct padding', () => {
      const { getByRole } = render(
        <Button size="sm">Small</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.padding).toBe('8px 16px');
    });

    it('renders medium size with correct padding', () => {
      const { getByRole } = render(
        <Button size="md">Medium</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.padding).toBe('12px 24px');
    });

    it('renders large size with correct padding', () => {
      const { getByRole } = render(
        <Button size="lg">Large</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.padding).toBe('16px 32px');
    });
  });

  describe('Typography - Requirement 9.4', () => {
    it('uses 14px uppercase text with 0.1em letter spacing', () => {
      const { getByRole } = render(
        <Button>Click Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.fontSize).toBe('14px');
      expect(button.style.textTransform).toBe('uppercase');
      expect(button.style.letterSpacing).toBe('0.1em');
      expect(button.style.fontWeight).toBe('700');
    });
  });

  describe('Disabled State - Requirement 9.8', () => {
    it('applies 50% opacity when disabled', () => {
      const { getByRole } = render(
        <Button disabled>Disabled</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      expect(button.style.opacity).toBe('0.5');
      expect(button.style.cursor).toBe('not-allowed');
      expect(button.disabled).toBe(true);
    });

    it('does not apply hover effects when disabled', () => {
      const { getByRole } = render(
        <Button disabled>Disabled</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseEnter(button);
      
      expect(button.style.transform).toBe('translate(0, 0)');
    });

    it('does not apply pressed effects when disabled', () => {
      const { getByRole } = render(
        <Button disabled>Disabled</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseDown(button);
      
      expect(button.style.transform).toBe('translate(0, 0)');
    });
  });

  describe('Hover Effects - Requirement 9.5, 18.1', () => {
    it('translates 3px down-right on hover', () => {
      const { getByRole } = render(
        <Button variant="primary">Hover Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseEnter(button);
      
      expect(button.style.transform).toBe('translate(3px, 3px)');
    });

    it('reduces shadow offset by 3px on hover for primary variant', () => {
      const { getByRole } = render(
        <Button variant="primary">Hover Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseEnter(button);
      
      expect(button.style.boxShadow).toContain('3px 3px');
    });

    it('reduces shadow offset by 3px on hover for secondary variant', () => {
      const { getByRole } = render(
        <Button variant="secondary">Hover Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseEnter(button);
      
      expect(button.style.boxShadow).toContain('1px 1px');
    });

    it('resets transform on mouse leave', () => {
      const { getByRole } = render(
        <Button variant="primary">Hover Me</Button>,
        { wrapper }
      );
      const button = getByRole('button');
      
      fireEvent.mouseEnter(button);
      fireEvent.mouseLeave(button);
      
      expect(button.style.transform).toBe('translate(0, 0)');
    });
  });

