'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism, ShadowColor } from '../styles/tokens';

export interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Shadow color variant (cyan, purple, gold) */
  shadowColor?: ShadowColor;
  /** Optional rotation in degrees (-2 to 2) for playful asymmetry */
  rotation?: number;
  /** Whether the card has interactive hover effects */
  interactive?: boolean;
  /** Header section content */
  header?: React.ReactNode;
  /** Footer section content */
  footer?: React.ReactNode;
  /** Border radius (0px default, 4px for badges) */
  borderRadius?: '0px' | '4px';
  /** Custom padding */
  padding?: string;
}

/**
 * Card component with Neo Brutalism Gaming styling.
 *
 * Features:
 * - 3px solid black borders
 * - 6px offset shadows with configurable colors (cyan, purple, gold)
 * - Optional rotation (-2deg to 2deg) for playful asymmetry
 * - Support for header, body, and footer sections
 * - 0px border radius by default, optional 4px for badges
 * - Interactive hover effects (scale 1.03x, colored glow border)
 *
 * @see Requirements 10.1, 10.2, 10.3, 10.5, 10.6, 10.7, 10.8
 */
export const Card = forwardRef<HTMLDivElement, CardProps>(
  (
    {
      shadowColor = 'purple',
      rotation = 0,
      interactive = false,
      header,
      footer,
      borderRadius = '0px',
      padding = '24px',
      style,
      children,
      className,
      ...props
    },
    ref
  ) => {
    const { colors } = useTheme();

    // Clamp rotation to -2 to 2 degrees
    const clampedRotation = Math.max(-2, Math.min(2, rotation));

    // Get shadow preset based on color
    const shadowPreset = neoBrutalism.shadows.presets[`${shadowColor}Md`];

    const cardStyle: React.CSSProperties = {
      backgroundColor: colors.panel,
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      borderRadius: borderRadius,
      boxShadow: shadowPreset,
      padding: 0, // Remove default padding, let sections handle it
      transform: `rotate(${clampedRotation}deg)`,
      transition: interactive
        ? `transform ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}, box-shadow ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}`
        : '',
      position: 'relative',
      ...style,
    };

    const headerStyle: React.CSSProperties = {
      padding: padding,
      borderBottom: header && (children || footer) ? `${neoBrutalism.borders.width.default} solid ${colors.border}` : undefined,
      fontFamily: neoBrutalism.typography.subheading.family,
      fontSize: neoBrutalism.typography.subheading.size,
      fontWeight: neoBrutalism.typography.subheading.weight,
      lineHeight: neoBrutalism.typography.subheading.lineHeight,
    };

    const bodyStyle: React.CSSProperties = {
      padding: padding,
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: neoBrutalism.typography.body.size,
      lineHeight: neoBrutalism.typography.body.lineHeight,
    };

    const footerStyle: React.CSSProperties = {
      padding: padding,
      borderTop: footer && (header || children) ? `${neoBrutalism.borders.width.default} solid ${colors.border}` : undefined,
      fontSize: neoBrutalism.typography.label.size,
      color: colors.textSecondary,
    };

    // Interactive hover styles
    const interactiveClassName = interactive ? 'card-interactive' : '';
    const combinedClassName = `${interactiveClassName} ${className || ''}`.trim();

    return (
      <>
        {interactive && (
          <style>{`
            .card-interactive:hover {
              transform: scale(1.03) rotate(${clampedRotation}deg) !important;
              box-shadow: 0 0 20px ${neoBrutalism.shadows.color[shadowColor]} !important;
            }
          `}</style>
        )}
        <div
          ref={ref}
          style={cardStyle}
          className={combinedClassName}
          {...props}
        >
          {header && <div style={headerStyle}>{header}</div>}
          {children && <div style={bodyStyle}>{children}</div>}
          {footer && <div style={footerStyle}>{footer}</div>}
        </div>
      </>
    );
  }
);

Card.displayName = 'Card';

import { describe, it, expect } from 'vitest';
import { render } from '@testing-library/react';
import '@testing-library/jest-dom/vitest';
import { Card } from './Card';
import { ThemeProvider } from '../providers/ThemeProvider';

const wrapper = ({ children }: { children: React.ReactNode }) => (
  <ThemeProvider>{children}</ThemeProvider>
);

describe('Card Component', () => {
  describe('Basic Rendering', () => {
    it('renders with default props', () => {
      const { container } = render(
        <Card>Test Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card).toBeTruthy();
      expect(card.textContent).toContain('Test Content');
    });

    it('applies 3px solid border', () => {
      const { container } = render(
        <Card>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.border).toContain('3px');
      expect(card.style.border).toContain('solid');
    });

    it('applies 0px border radius by default', () => {
      const { container } = render(
        <Card>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.borderRadius).toBe('0px');
    });

    it('applies 4px border radius when specified', () => {
