  describe('Shadow Colors', () => {
    it('applies purple shadow by default', () => {
      const { container } = render(
        <Card>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.boxShadow).toBe('6px 6px 0px rgba(155, 92, 255, 0.4)');
    });

    it('applies cyan shadow when specified', () => {
      const { container } = render(
        <Card shadowColor="cyan">Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.boxShadow).toBe('6px 6px 0px rgba(0, 229, 255, 0.4)');
    });

    it('applies gold shadow when specified', () => {
      const { container } = render(
        <Card shadowColor="gold">Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.boxShadow).toBe('6px 6px 0px rgba(255, 213, 74, 0.4)');
    });

    it('applies black shadow when specified', () => {
      const { container } = render(
        <Card shadowColor="black">Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.boxShadow).toBe('6px 6px 0px rgba(0, 0, 0, 1)');
    });
  });

  describe('Rotation', () => {
    it('applies no rotation by default', () => {
      const { container } = render(
        <Card>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transform).toBe('rotate(0deg)');
    });

    it('applies positive rotation within range', () => {
      const { container } = render(
        <Card rotation={1.5}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transform).toBe('rotate(1.5deg)');
    });

    it('applies negative rotation within range', () => {
      const { container } = render(
        <Card rotation={-1.5}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transform).toBe('rotate(-1.5deg)');
    });

    it('clamps rotation to maximum 2 degrees', () => {
      const { container } = render(
        <Card rotation={5}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transform).toBe('rotate(2deg)');
    });

    it('clamps rotation to minimum -2 degrees', () => {
      const { container } = render(
        <Card rotation={-5}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transform).toBe('rotate(-2deg)');
    });
  });

  describe('Sections', () => {
    it('renders header section when provided', () => {
      const { container } = render(
        <Card header={<div>Header Content</div>}>Body Content</Card>,
        { wrapper }
      );
      
      expect(container.textContent).toContain('Header Content');
      expect(container.textContent).toContain('Body Content');
    });

    it('renders footer section when provided', () => {
      const { container } = render(
        <Card footer={<div>Footer Content</div>}>Body Content</Card>,
        { wrapper }
      );
      
      expect(container.textContent).toContain('Footer Content');
      expect(container.textContent).toContain('Body Content');
    });

    it('renders all three sections together', () => {
      const { container } = render(
        <Card 
          header={<div>Header</div>}
          footer={<div>Footer</div>}
        >
          Body
        </Card>,
        { wrapper }
      );
      
      expect(container.textContent).toContain('Header');
      expect(container.textContent).toContain('Body');
      expect(container.textContent).toContain('Footer');
    });

    it('renders only body when no header or footer provided', () => {
      const { getByText } = render(
        <Card>Only Body</Card>,
        { wrapper }
      );
      
      expect(getByText('Only Body')).toBeTruthy();
    });
  });

  describe('Interactive Behavior', () => {
    it('does not apply transitions when not interactive', () => {
      const { container } = render(
        <Card interactive={false}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.transition).toBe('');
    });

    it('applies transitions when interactive', () => {
      const { container } = render(
        <Card interactive={true}>Content</Card>,
        { wrapper }
      );
      
      // When interactive, there's a style tag first, so we need to get the div
      const card = container.querySelector('div[class*="card-interactive"]') as HTMLElement;
      expect(card).toBeTruthy();
      expect(card.style.transition).toContain('transform');
      expect(card.style.transition).toContain('box-shadow');
    });

    it('adds interactive class when interactive prop is true', () => {
      const { container } = render(
        <Card interactive={true}>Content</Card>,
        { wrapper }
      );
      
      const card = container.querySelector('div[class*="card-interactive"]') as HTMLElement;
      expect(card).toBeTruthy();
      expect(card.className).toContain('card-interactive');
    });

    it('does not add interactive class when interactive prop is false', () => {
      const { container } = render(
        <Card interactive={false}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.className).not.toContain('card-interactive');
    });
  });

  describe('Custom Styling', () => {
    it('applies custom padding', () => {
      const { container } = render(
        <Card padding="32px">Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      const bodySection = card.querySelector('div');
      expect(bodySection?.style.padding).toBe('32px');
    });

    it('merges custom styles with default styles', () => {
      const { container } = render(
        <Card style={{ backgroundColor: 'red' }}>Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.style.backgroundColor).toBe('red');
    });

    it('applies custom className', () => {
      const { container } = render(
        <Card className="custom-class">Content</Card>,
        { wrapper }
      );
      
      const card = container.firstChild as HTMLElement;
      expect(card.className).toContain('custom-class');
    });
  });
});

'use client';

import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type BadgeVariant = 'purple' | 'cyan' | 'gold' | 'default';
export type BadgeSize = 'sm' | 'md' | 'lg';

export interface BadgeProps extends React.HTMLAttributes<HTMLSpanElement> {
  /** Visual variant - color scheme for the badge */
  variant?: BadgeVariant;
  /** Size preset */
  size?: BadgeSize;
  /** Optional rotation in degrees (-2 to 2 for playful asymmetry) */
  rotation?: number;
}

const badgeSizeStyles: Record<BadgeSize, React.CSSProperties> = {
  sm: { padding: '2px 8px', fontSize: '11px' },
  md: { padding: '4px 12px', fontSize: '12px' },
  lg: { padding: '6px 16px', fontSize: '14px' },
};

/**
 * Badge component for role tags and season labels with Neo Brutalism Gaming styling.
 *
 * Features:
 * - 3px purple border with 4px shadow
 * - Support for rotation (-2deg to 2deg) for playful asymmetry
 * - 12px font size for labels
 * - Color variants (purple, cyan, gold)
 * - 4px border radius for subtle rounding
 *
 * @see Requirements 3.6, 4.8, 8.2
 */
export const Badge = forwardRef<HTMLSpanElement, BadgeProps>(
  ({ variant = 'purple', size = 'md', rotation = 0, style, children, ...props }, ref) => {
    const { mode, colors } = useTheme();

    // Define color variants with appropriate backgrounds and shadows
    const variantColors: Record<BadgeVariant, { bg: string; text: string; shadow: string }> = {
      purple: {
        bg: colors.accentPurple,
        text: '#FFFFFF',
        shadow: neoBrutalism.shadows.presets.purpleSm,
      },
      cyan: {
        bg: colors.accentCyan,
        text: mode === 'dark' ? '#0A0A0A' : '#FFFFFF',
        shadow: neoBrutalism.shadows.presets.cyanSm,
      },
      gold: {
        bg: colors.accentGold,
        text: '#0A0A0A',
        shadow: neoBrutalism.shadows.presets.goldSm,
      },
      default: {
        bg: colors.panel,
        text: colors.textPrimary,
        shadow: `${neoBrutalism.shadows.offset.sm} 0px ${neoBrutalism.shadows.color[mode]}`,
      },
    };

    const { bg, text, shadow } = variantColors[variant];

    const badgeStyle: React.CSSProperties = {
      display: 'inline-flex',
      alignItems: 'center',
      fontFamily: neoBrutalism.typography.body.family,
      fontWeight: 700,
      textTransform: 'uppercase',
      letterSpacing: '0.05em',
      backgroundColor: bg,
      color: text,
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      borderRadius: neoBrutalism.borders.radius.subtle, // 4px for subtle rounding
      boxShadow: shadow,
      whiteSpace: 'nowrap',
      transform: rotation !== 0 ? `rotate(${rotation}deg)` : undefined,
      ...badgeSizeStyles[size],
      ...style,
    };

    return (
      <span ref={ref} style={badgeStyle} {...props}>
        {children}
      </span>
    );
  }
);

