'use client';

import React, { useEffect, useState, Suspense } from 'react';
import Link from 'next/link';
import { motion } from 'framer-motion';
import dynamic from 'next/dynamic';
import { neoBrutalism } from '@perfect-world/ui/styles/tokens';

// Dynamically import HeroScene3D to avoid SSR issues with React Three Fiber
const HeroScene3D = dynamic(() => import('./HeroScene3D').then(mod => ({ default: mod.HeroScene3D })), {
  ssr: false,
  loading: () => <HeroLoadingPlaceholder />,
});

/**
 * HeroSection Component
 *
 * Implements the homepage hero section with Neo-Brutalism Gaming aesthetic:
 * - Component with TypeScript interface for props
 * - Parallax background layers (0.3x and 0.5x speeds)
 * - Container for 3D scene integration with WebGL fallback
 * - Hero content container with proper z-index layering
 * - "ENTER THE PERFECT WORLD" heading (Anton, 72px desktop / 36px mobile)
 * - React Three Fiber 3D scene with floating islands, clouds, particles (60fps target)
 * - Call-to-action buttons: "PLAY NOW", "DOWNLOAD LAUNCHER"
 * - Online player count display
 *
 * @see Requirements 5.1, 5.2, 5.8
 */

/**
 * HeroSection Props Interface
 * Defines the component's external API
 */
interface HeroSectionProps {
  /** Number of players currently online */
  onlinePlayerCount?: number;
  /** Loading state for player count */
  isLoadingPlayerCount?: boolean;
}

/**
 * Loading Placeholder Component
 * Displays while 3D scene is loading, preserving layout
 */
function HeroLoadingPlaceholder() {
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: neoBrutalism.colors.dark.background,
        zIndex: 1,
      }}
    >
      <div style={{ textAlign: 'center' }}>
        <div
          style={{
            width: '48px',
            height: '48px',
            border: `${neoBrutalism.borders.width.default} solid ${neoBrutalism.colors.dark.border}`,
            borderTop: `${neoBrutalism.borders.width.default} solid ${neoBrutalism.colors.dark.accentCyan}`,
            borderRadius: '50%',
            animation: 'spin 1s linear infinite',
            margin: '0 auto 16px',
          }}
        />
        <p style={{ 
          color: neoBrutalism.colors.dark.textSecondary, 
          fontSize: neoBrutalism.typography.label.size, 
          margin: 0 
        }}>
          Loading 3D Scene...
        </p>
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

/**
 * Fallback Static Image Component
 * Displays when WebGL is not supported
 */
function HeroFallback() {
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        backgroundImage:
          'url(https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=1920&q=80)',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundAttachment: 'fixed',
        zIndex: 0,
      }}
      aria-label="Hero background image"
    />
  );
}

/**
 * Parallax Background Layer Component
 * Implements parallax scrolling effect at configurable speeds
 * 
 * @param offset - Initial offset position
 * @param speed - Parallax speed multiplier (0.3x or 0.5x for requirements)
 * @param children - Content to render in the parallax layer
 */
function ParallaxLayer({
  offset,
  speed,
  children,
}: {
  offset: number;
  speed: number;
  children: React.ReactNode;
}) {
  const [scrollY, setScrollY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        transform: `translateY(${scrollY * speed}px)`,
        willChange: 'transform',
        zIndex: 1,
      }}
    >
      {children}
    </div>
  );
}

/**
 * Vignette Overlay Component
 * Adds depth and focus to the hero section
 */
function VignetteOverlay() {
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        background:
          'radial-gradient(ellipse at center, rgba(10,10,10,0.3) 0%, rgba(10,10,10,0.85) 100%)',
        pointerEvents: 'none',
        zIndex: 2,
      }}
      aria-hidden="true"
    />
  );
}

/**
 * Bottom Fade Overlay Component
 * Creates smooth transition to content below
 */
function BottomFadeOverlay() {
  return (
    <div
      style={{
        position: 'absolute',
        bottom: 0,
        left: 0,
        right: 0,
        height: '200px',
        background: `linear-gradient(to top, ${neoBrutalism.colors.dark.background} 0%, transparent 100%)`,
        pointerEvents: 'none',
        zIndex: 3,
      }}
      aria-hidden="true"
    />
  );
}

/**
 * CTA Button Component
 * Neo-Brutalism styled call-to-action button
 * 
 * @param href - Link destination
 * @param variant - Button style variant (primary or secondary)
 * @param children - Button text content
 */
function CTAButton({
  href,
  variant = 'primary',
  children,
}: {
  href: string;
  variant?: 'primary' | 'secondary';
  children: React.ReactNode;
}) {
  const isPrimary = variant === 'primary';

  return (
    <motion.div
      whileHover={{ y: -2 }}
      whileTap={{ y: 0 }}
      transition={{ duration: 0.2 }}
    >
      <Link
        href={href}
        style={{
          display: 'inline-block',
          padding: '16px 48px',
          background: isPrimary ? neoBrutalism.colors.dark.accentCyan : 'transparent',
          color: isPrimary ? neoBrutalism.colors.dark.background : neoBrutalism.colors.dark.accentCyan,
          border: `${neoBrutalism.borders.width.default} solid ${neoBrutalism.colors.dark.accentCyan}`,
          fontSize: neoBrutalism.typography.button.size,
          fontWeight: neoBrutalism.typography.button.weight,
          letterSpacing: neoBrutalism.typography.button.letterSpacing,
          textTransform: neoBrutalism.typography.button.textTransform,
          textDecoration: 'none',
          cursor: 'pointer',
          transition: `all ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}`,
          boxShadow: isPrimary ? neoBrutalism.shadows.presets.cyanSm : 'none',
        }}
        onMouseEnter={(e) => {
          const el = e.currentTarget as HTMLAnchorElement;
          if (isPrimary) {
            el.style.background = '#33EDFF';
            el.style.boxShadow = neoBrutalism.shadows.presets.cyanMd;
          } else {
            el.style.background = 'rgba(0, 229, 255, 0.1)';
            el.style.boxShadow = neoBrutalism.shadows.presets.cyanSm;
          }
        }}
        onMouseLeave={(e) => {
          const el = e.currentTarget as HTMLAnchorElement;
          if (isPrimary) {
            el.style.background = neoBrutalism.colors.dark.accentCyan;
            el.style.boxShadow = neoBrutalism.shadows.presets.cyanSm;
          } else {
            el.style.background = 'transparent';
            el.style.boxShadow = 'none';
          }
        }}
      >
        {children}
      </Link>
    </motion.div>
  );
}

/**
 * Watch Trailer Link Component
 * Secondary action link for video content
 */
function WatchTrailerLink() {
  return (
    <motion.div
      whileHover={{ x: 4 }}
      transition={{ duration: 0.2 }}
    >
      <Link
        href="#"
        onClick={(e) => e.preventDefault()}
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: neoBrutalism.spacing.xs,
          fontSize: neoBrutalism.typography.button.size,
          fontWeight: neoBrutalism.typography.body.weightBold,
          color: neoBrutalism.colors.dark.textSecondary,
          textDecoration: 'none',
          transition: `color ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}`,
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.color = neoBrutalism.colors.dark.accentCyan;
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.color = neoBrutalism.colors.dark.textSecondary;
        }}
      >
        ▶ WATCH TRAILER
      </Link>
    </motion.div>
  );
}

/**
 * Online Player Count Component
 * Displays current online player count with pulsing indicator
 * 
 * @param count - Number of players online
 * @param isLoading - Loading state
 */
function OnlinePlayerCount({
  count,
  isLoading,
}: {
  count?: number;
  isLoading?: boolean;
}) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.6, duration: 0.5 }}
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: neoBrutalism.spacing.xs,
        fontSize: neoBrutalism.typography.label.size,
        color: neoBrutalism.colors.dark.textSecondary,
        marginTop: neoBrutalism.spacing.sm,
      }}
    >
      <span
        style={{
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: '#22C55E',
          boxShadow: '0 0 8px rgba(34, 197, 94, 0.5)',
          animation: 'pulse 2s ease-in-out infinite',
        }}
      />
      {isLoading ? (
        <span>Loading player count...</span>
      ) : (
        <span>
          {count?.toLocaleString() || '0'} players online
        </span>
      )}
      <style jsx>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </motion.div>
  );
}

/**
 * Main HeroSection Component
 * 
 * Implements the hero section with:
 * - TypeScript interface for props (HeroSectionProps)
 * - Parallax background layers at 0.3x and 0.5x speeds
 * - Container for 3D scene integration with WebGL detection and fallback
 * - Hero content container with proper z-index layering (z-index: 10)
 * - Responsive layout and animations
 * 
 * @param props - HeroSectionProps
 * @returns Hero section component
 */
export function HeroSection({
  onlinePlayerCount,
  isLoadingPlayerCount,
}: HeroSectionProps) {
  const [scrollY, setScrollY] = useState(0);
  const [webGLSupported, setWebGLSupported] = useState(true);
  const [sceneLoaded, setSceneLoaded] = useState(false);

  // Check WebGL support on mount
  useEffect(() => {
    try {
      const canvas = document.createElement('canvas');
      const gl =
        canvas.getContext('webgl2') || canvas.getContext('webgl');
      setWebGLSupported(!!gl);
    } catch {
      setWebGLSupported(false);
    }
  }, []);

  // Track scroll for parallax effects
  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <section
      style={{
        position: 'relative',
        width: '100%',
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        overflow: 'hidden',
        background: neoBrutalism.colors.dark.background,
      }}
      aria-label="Hero section"
    >
      {/* 3D Scene Container - z-index: 0 */}
      {webGLSupported ? (
        <>
          <Suspense fallback={<HeroLoadingPlaceholder />}>
            <div
              style={{
                position: 'absolute',
                inset: 0,
                zIndex: 0,
              }}
              onLoad={() => setSceneLoaded(true)}
            >
              <HeroScene3D />
            </div>
          </Suspense>
          {!sceneLoaded && <HeroLoadingPlaceholder />}
        </>
      ) : (
        <HeroFallback />
      )}

      {/* Parallax Layer 1 - Slower movement (0.3x speed) - z-index: 1 */}
      <ParallaxLayer offset={0} speed={0.3}>
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background:
              'radial-gradient(ellipse at center, rgba(0, 229, 255, 0.05) 0%, transparent 70%)',
            pointerEvents: 'none',
          }}
          aria-hidden="true"
        />
      </ParallaxLayer>

      {/* Parallax Layer 2 - Faster movement (0.5x speed) - z-index: 1 */}
      <ParallaxLayer offset={0} speed={0.5}>
        <div
          style={{
            position: 'absolute',
            inset: 0,
            background:
              'radial-gradient(ellipse at center, rgba(155, 92, 255, 0.03) 0%, transparent 80%)',
            pointerEvents: 'none',
          }}
          aria-hidden="true"
        />
      </ParallaxLayer>

      {/* Vignette and overlays - z-index: 2-3 */}
      <VignetteOverlay />
      <BottomFadeOverlay />

      {/* Hero Content Container - z-index: 10 for proper layering above all backgrounds */}
      <motion.div
