/**
 * Parallax Background Layer Component
 * Implements parallax scrolling effect at configurable speeds
 * 
 * @param offset - Initial offset position
 * @param speed - Parallax speed multiplier (0.3x or 0.5x for requirements)
 * @param children - Content to render in the parallax layer
 */
function ParallaxLayer({
  offset,
  speed,
  children,
}: {
  offset: number;
  speed: number;
  children: React.ReactNode;
}) {
  const [scrollY, setScrollY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        transform: `translateY(${scrollY * speed}px)`,
        willChange: 'transform',
        zIndex: 1,
      }}
    >
      {children}
    </div>
  );
}

/**
 * Vignette Overlay Component
 * Adds depth and focus to the hero section
