import React, { useRef, Suspense } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Float, Stars, MeshDistortMaterial, MeshWobbleMaterial, Sparkles } from '@react-three/drei';
import * as THREE from 'three';

// Floating Island component
function FloatingIsland({ position, scale, color }: { position: [number, number, number]; scale: number; color: string }) {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += 0.002;
      meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.5) * 0.3;
    }
  });

  return (
    <Float speed={1.5} rotationIntensity={0.2} floatIntensity={0.5}>
      <mesh ref={meshRef} position={position} scale={scale}>
        <dodecahedronGeometry args={[1, 0]} />
        <MeshDistortMaterial
          color={color}
          speed={2}
          distort={0.3}
          roughness={0.4}
          metalness={0.8}
        />
      </mesh>
    </Float>
  );
}

// Glowing Crystal component
function Crystal({ position, color, scale = 1 }: { position: [number, number, number]; color: string; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += 0.01;
      meshRef.current.rotation.z = Math.sin(state.clock.elapsedTime) * 0.1;
    }
  });

  return (
    <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
      <mesh ref={meshRef} position={position} scale={scale}>
        <octahedronGeometry args={[0.5, 0]} />
        <meshStandardMaterial
          color={color}
          emissive={color}
          emissiveIntensity={2}
          roughness={0.1}
          metalness={0.9}
          transparent
          opacity={0.8}
        />
      </mesh>
      {/* Glow effect */}
      <mesh position={position} scale={scale * 1.5}>
        <octahedronGeometry args={[0.5, 0]} />
        <meshBasicMaterial color={color} transparent opacity={0.1} />
      </mesh>
    </Float>
  );
}

// Magical Portal Ring
function PortalRing() {
  const ringRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (ringRef.current) {
      ringRef.current.rotation.z += 0.005;
      ringRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.3) * 0.2;
    }
  });

  return (
    <mesh ref={ringRef} position={[0, 0, -5]}>
      <torusGeometry args={[3, 0.05, 16, 100]} />
      <meshStandardMaterial
        color="#00e5ff"
        emissive="#00e5ff"
        emissiveIntensity={3}
        roughness={0}
        metalness={1}
      />
    </mesh>
  );
}

// Terrain/Ground
function Terrain() {
  const meshRef = useRef<THREE.Mesh>(null);

  return (
    <mesh ref={meshRef} rotation={[-Math.PI / 2, 0, 0]} position={[0, -3, 0]}>
      <planeGeometry args={[50, 50, 64, 64]} />
      <MeshWobbleMaterial
        color="#0a0a2e"
        factor={0.2}
        speed={0.5}
        roughness={1}
        metalness={0}
      />
    </mesh>
  );
}

// Camera animation
function CameraRig() {
  useFrame((state) => {
    state.camera.position.x = Math.sin(state.clock.elapsedTime * 0.1) * 0.5;
    state.camera.position.y = 0.5 + Math.sin(state.clock.elapsedTime * 0.2) * 0.2;
    state.camera.lookAt(0, 0, -2);
  });
  return null;
}

// Main Scene with performance optimizations
function Scene() {
  return (
    <>
      {/* Lighting */}
      <ambientLight intensity={0.2} />
      <pointLight position={[5, 5, 5]} intensity={1} color="#00e5ff" />
      <pointLight position={[-5, 3, -5]} intensity={0.8} color="#b44aff" />
      <pointLight position={[0, -2, 3]} intensity={0.5} color="#ffd700" />
      <directionalLight position={[0, 10, 5]} intensity={0.3} color="#ffffff" />

      {/* Stars background - reduced count for performance */}
      <Stars radius={100} depth={50} count={3000} factor={4} saturation={0} fade speed={1} />

      {/* Sparkles - reduced count for performance */}
      <Sparkles count={50} scale={15} size={2} speed={0.4} color="#00e5ff" />
      <Sparkles count={30} scale={10} size={3} speed={0.3} color="#b44aff" />
      <Sparkles count={20} scale={8} size={4} speed={0.2} color="#ffd700" />

      {/* Floating Islands - reduced count for performance */}
      <FloatingIsland position={[-3, 1, -8]} scale={1.5} color="#1a1a3e" />
      <FloatingIsland position={[4, -0.5, -10]} scale={2} color="#0f0f2a" />
      <FloatingIsland position={[-1, 2, -12]} scale={1} color="#1a0a2e" />

      {/* Crystals - reduced count for performance */}
      <Crystal position={[-2, 2, -5]} color="#00e5ff" scale={0.6} />
      <Crystal position={[3, 1.5, -7]} color="#b44aff" scale={0.8} />
      <Crystal position={[0, 3, -9]} color="#ffd700" scale={0.5} />

      {/* Portal Ring */}
      <PortalRing />

      {/* Fog */}
      <fog attach="fog" args={['#0a0a0f', 5, 25]} />

      {/* Terrain */}
      <Terrain />

      {/* Camera animation */}
      <CameraRig />
    </>
  );
}

// Loading fallback
function LoadingFallback() {
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: '#0a0a0f',
      }}
    >
      <div style={{ textAlign: 'center' }}>
        <div
          style={{
            width: '40px',
            height: '40px',
            border: '3px solid #2a2a3a',
            borderTop: '3px solid #00e5ff',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite',
            margin: '0 auto 16px',
          }}
        />
        <p style={{ color: '#8b8ba3', fontSize: '14px' }}>Loading 3D Scene...</p>
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

// Exported component with performance optimizations
export function HeroScene3D() {
  return (
    <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
      <Suspense fallback={<LoadingFallback />}>
        <Canvas
          camera={{ position: [0, 0.5, 5], fov: 60 }}
          style={{ background: '#0a0a0f' }}
          gl={{ 
            antialias: true, 
            alpha: false,
            powerPreference: 'high-performance', // Prefer high-performance GPU
          }}
          dpr={[1, 1.5]} // Limit pixel ratio for better performance
          performance={{ min: 0.5 }} // Allow quality reduction if FPS drops
          frameloop="demand" // Only render when needed
        >
          <Scene />
        </Canvas>
      </Suspense>
    </div>
  );
}

