'use client';

import React from 'react';
import { useTheme } from '@perfect-world/ui/providers/ThemeProvider';
import { neoBrutalism } from '@perfect-world/ui/styles/tokens';
import { Badge } from '@perfect-world/ui/components/Badge';
import type { ClassRole } from '../lib/class-showcase.logic';

/**
 * Role icon mapping for class categorization
 */
const ROLE_ICONS: Record<ClassRole, string> = {
  tank: '🛡️',
  healer: '✨',
  damage_dealer: '⚔️',
  support: '🔮',
};

const ROLE_LABELS: Record<ClassRole, string> = {
  tank: 'Tank',
  healer: 'Healer',
  damage_dealer: 'Damage Dealer',
  support: 'Support',
};

export interface ClassCardProps {
  /** Unique identifier for the class */
  id: string;
  /** Class name displayed in Anton font at 24px */
  name: string;
  /** Role type for badge display */
  role: ClassRole;
  /** Class description text */
  description: string;
  /** URL to class artwork image */
  artwork: string;
  /** Optional list of primary abilities */
  primaryAbilities?: string[];
  /** Optional playstyle summary */
  playstyleSummary?: string;
  /** Whether the card is currently hovered */
  isHovered?: boolean;
  /** Rotation angle in degrees (-1 to 2 for playful asymmetry) */
  rotation?: number;
  /** Callback when card is hovered */
  onHover?: () => void;
  /** Callback when hover ends */
  onHoverOut?: () => void;
  /** Callback when card is clicked */
  onClick?: () => void;
}

/**
 * ClassCard Component
 *
 * Displays a single character class card with Neo-Brutalism Gaming styling.
 *
 * Features:
 * - 4px black borders and 6px purple offset shadows
 * - Class name in Anton font at 24px
 * - Role badge with 3px purple border, 4px shadow, -2deg rotation
 * - Class artwork with proper aspect ratio
 * - Hover effects: scale to 1.05x, cyan glow border, reveal abilities
 * - Random subtle rotations (-1deg to 2deg) for playful asymmetry
 *
 * @see Requirements 8.1, 8.2, 8.3
 */
export function ClassCard({
  id,
  name,
  role,
  description,
  artwork,
  primaryAbilities,
  playstyleSummary,
  isHovered = false,
  rotation = 0,
  onHover,
  onHoverOut,
  onClick,
}: ClassCardProps) {
  const { colors } = useTheme();

  return (
    <div
      data-testid={`class-card-${id}`}
      style={{
        position: 'relative',
        height: '500px',
        overflow: 'hidden',
        cursor: 'pointer',
        // Requirement 8.1: 4px black borders
        border: `${neoBrutalism.borders.width.heavy} solid ${colors.border}`,
        borderRadius: neoBrutalism.borders.radius.none,
        // Requirement 8.1: 6px purple offset shadows
        boxShadow: neoBrutalism.shadows.presets.purpleMd,
        backgroundColor: colors.panel,
        transition: `transform ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}, box-shadow ${neoBrutalism.animation.duration.normal} ${neoBrutalism.animation.easing.easeOut}`,
        // Requirement 8.6: Random subtle rotations (-1deg to 2deg) for playful asymmetry
        transform: isHovered ? 'scale(1.05)' : `rotate(${rotation}deg)`,
      }}
      onMouseEnter={onHover}
      onMouseLeave={onHoverOut}
      onClick={onClick}
    >
      {/* Artwork Background */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: `url(${artwork})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          transition: 'transform 0.3s ease',
          transform: isHovered ? 'scale(1.08)' : 'scale(1)',
        }}
      />

      {/* Overlay Gradient */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          background: `linear-gradient(to top, ${colors.panel} 0%, ${colors.panel}dd 40%, transparent 100%)`,
          transition: 'opacity 0.2s ease',
          opacity: isHovered ? 0.5 : 0.7,
        }}
      />

      {/* Requirement 8.4: Glow Border Effect on Hover - 0 0 20px cyan glow */}
      {isHovered && (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            border: `${neoBrutalism.borders.width.default} solid ${colors.accentCyan}`,
            borderRadius: neoBrutalism.borders.radius.none,
            boxShadow: `inset 0 0 20px ${colors.accentCyan}40, 0 0 20px ${colors.accentCyan}60`,
            pointerEvents: 'none',
            animation: 'glowPulse 0.6s ease-in-out',
          }}
        />
      )}

      {/* Content Container */}
      <div
        style={{
          position: 'absolute',
          bottom: 0,
          left: 0,
          right: 0,
          padding: '32px 24px',
          zIndex: 10,
        }}
      >
        {/* Requirement 8.2: Role badge with 3px purple border, 4px shadow, -2deg rotation */}
        <div
          style={{
            display: 'inline-block',
            marginBottom: '12px',
            transform: 'rotate(-2deg)',
          }}
        >
          <Badge
            variant="purple"
            size="md"
            rotation={0} // Already rotated by parent div
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: '6px',
            }}
          >
            <span>{ROLE_ICONS[role]}</span>
            <span>{ROLE_LABELS[role]}</span>
          </Badge>
        </div>

        {/* Requirement 8.3: Class name in Anton font at 24px */}
        <h3
          style={{
            fontSize: neoBrutalism.typography.subheading.size, // 24px
            fontWeight: neoBrutalism.typography.subheading.weight,
            margin: '0 0 8px 0',
            color: colors.textPrimary,
            fontFamily: neoBrutalism.typography.subheading.family, // Anton
            transition: 'text-shadow 0.2s ease',
            // Requirement 8.3: Cyan text shadow on hover
            textShadow: isHovered
              ? `0 0 20px ${colors.accentCyan}80`
              : 'none',
          }}
        >
          {name}
        </h3>

        {/* Description */}
        <p
          style={{
            fontSize: '13px',
            color: colors.textSecondary,
            margin: 0,
            lineHeight: 1.5,
            maxHeight: isHovered ? '100px' : '50px',
            overflow: 'hidden',
            transition: 'max-height 0.2s ease',
          }}
        >
          {description}
        </p>

        {/* Requirement 8.5: Reveal primary abilities within 200ms on hover */}
        {isHovered && primaryAbilities && (
          <div
            style={{
              marginTop: '12px',
              paddingTop: '12px',
              borderTop: `1px solid ${colors.border}`,
              fontSize: '12px',
              color: colors.textSecondary,
              animation: 'fadeIn 0.2s ease',
            }}
          >
            <div style={{ fontWeight: 600, marginBottom: '6px' }}>
              Primary Abilities:
            </div>
            <ul
              style={{
                margin: 0,
                paddingLeft: '16px',
                listStyle: 'disc',
              }}
            >
              {primaryAbilities.slice(0, 2).map((ability, idx) => (
                <li key={idx}>{ability}</li>
              ))}
            </ul>
          </div>
        )}

        {isHovered && playstyleSummary && (
          <div
            style={{
              marginTop: '8px',
              fontSize: '12px',
              color: colors.textSecondary,
              fontStyle: 'italic',
              animation: 'fadeIn 0.2s ease',
            }}
          >
            {playstyleSummary}
          </div>
        )}
      </div>

      {/* Global Animations */}
      <style jsx global>{`
        @keyframes glowPulse {
          0%, 100% {
            box-shadow: inset 0 0 20px rgba(0, 229, 255, 0.4),
              0 0 20px rgba(0, 229, 255, 0.6);
          }
          50% {
            box-shadow: inset 0 0 30px rgba(0, 229, 255, 0.6),
              0 0 30px rgba(0, 229, 255, 0.8);
          }
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: translateY(-8px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
}

'use client';

import React, { useCallback, useEffect, useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme, neoBrutalism } from '@perfect-world/ui';

/** Navigation link definition */
interface NavLink {
  label: string;
  href: string;
}

const NAV_LINKS: NavLink[] = [
  { label: 'Home', href: '/' },
  { label: 'Download', href: '/download' },
  { label: 'News', href: '/news' },
  { label: 'Rankings', href: '/rankings' },
  { label: 'Guilds', href: '/guilds' },
  { label: 'Territory War', href: '/territory-war' },
  { label: 'Marketplace', href: '/marketplace' },
  { label: 'Wiki', href: '/wiki' },
  { label: 'Support', href: '/support' },
];

const AUTH_LINKS: NavLink[] = [
  { label: 'Login', href: '/login' },
];

/** Neo-Brutalism Gaming theme colors */
const NEO_BRUTALISM_THEME = {
  navBg: neoBrutalism.colors.dark.background,
  navBgScrolled: 'rgba(10, 10, 10, 0.85)',
  border: neoBrutalism.colors.dark.border,
  borderBlack: '#000000',
  cyan: neoBrutalism.colors.dark.accentCyan,
  linkInactive: neoBrutalism.colors.dark.textSecondary,
  linkHover: neoBrutalism.colors.dark.accentCyan,
  linkActive: neoBrutalism.colors.dark.accentCyan,
  buttonBg: neoBrutalism.colors.dark.accentCyan,
  buttonText: '#000000',
  buttonShadow: neoBrutalism.shadows.presets.cyanSm,
  mobilePanelBg: neoBrutalism.colors.dark.panel,
  hamburgerBg: neoBrutalism.colors.dark.panel,
  hamburgerIcon: neoBrutalism.colors.dark.textPrimary,
  logoGlow: '0 0 10px rgba(0, 229, 255, 0.6)',
  accentLineHeight: '2px',
  focusRingColor: neoBrutalism.colors.dark.accentCyan,
};

/** Slide-out panel animation duration in seconds (300ms) */
const PANEL_DURATION = 0.3;

/**
 * NavigationBar
 *
 * Persistent navigation bar with Neo-Brutalism Gaming styling:
 * - 4px black bottom border (Requirement 6.1)
 * - 2px cyan accent line on active page (Requirement 6.1)
 * - Perfect World logo with cyan color and 0 0 10px cyan glow (Requirement 6.2)
 * - Backdrop blur and semi-transparent background on scroll (Requirement 6.7)
 * - All required links (Home, Download, News, Rankings, Guilds, Territory War, Marketplace, Wiki, Support, Login, Play Now)
 * - Sticky positioning with backdrop blur on scroll
 * - Keyboard-focusable links with active page highlight
 * - Responsive hamburger menu at <768px with slide-out panel (300ms open/close)
 *
 * Neo-Brutalism Gaming theme — bold, thick borders, offset shadows, cyan accents.
 *
 * @see Requirements 6.1, 6.2, 6.7
 */
export function NavigationBar() {
  const pathname = usePathname();
  const { mode } = useTheme();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Track scroll position for sticky backdrop blur
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 0);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    // Check initial scroll position
    handleScroll();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [pathname]);

  // Close mobile menu on Escape key
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isMobileMenuOpen) {
        setIsMobileMenuOpen(false);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isMobileMenuOpen]);

  // Prevent body scroll when mobile menu is open
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [isMobileMenuOpen]);

  const toggleMobileMenu = useCallback(() => {
    setIsMobileMenuOpen((prev) => !prev);
  }, []);

  const isActive = (href: string) => {
    if (href === '/') return pathname === '/';
    return pathname.startsWith(href);
  };

  return (
    <>
      <nav
        role="navigation"
        aria-label="Main navigation"
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-200 ${
          isScrolled
            ? 'backdrop-blur-md'
            : ''
        }`}
        style={{
          backgroundColor: isScrolled
            ? NEO_BRUTALISM_THEME.navBgScrolled
            : NEO_BRUTALISM_THEME.navBg,
          borderBottom: `${neoBrutalism.borders.width.heavy} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
        }}
      >
        <div className="mx-auto max-w-[1440px] px-4 md:px-6 lg:px-8">
          <div className="flex h-16 items-center justify-between">
            {/* Logo - Home Link with cyan color and 0 0 10px cyan glow (Requirement 6.2) */}
            <Link
              href="/"
              className="flex items-center gap-2 text-xl font-bold focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
              style={{
                color: NEO_BRUTALISM_THEME.cyan,
                fontFamily: neoBrutalism.typography.heading.family,
                textShadow: NEO_BRUTALISM_THEME.logoGlow,
                outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
              }}
              aria-label="Perfect World - Home"
            >
              <PerfectWorldLogo color={NEO_BRUTALISM_THEME.cyan} />
              <span className="hidden sm:inline">PERFECT WORLD</span>
            </Link>

            {/* Desktop Navigation Links */}
            <div className="hidden md:flex items-center gap-1">
              {NAV_LINKS.map((link) => (
                <NavItem
                  key={link.href}
                  link={link}
                  isActive={isActive(link.href)}
                />
              ))}
              {AUTH_LINKS.map((link) => (
                <NavItem
                  key={link.href}
                  link={link}
                  isActive={isActive(link.href)}
                />
              ))}
              {/* Play Now CTA Button with cyan background, 3px black border, 4px cyan shadow (Requirement 6.4) */}
              <Link
                href="/play"
                className="ml-2 px-4 py-2 font-bold text-sm uppercase tracking-wide transition-all duration-150 hover:translate-x-[3px] hover:translate-y-[3px] focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2"
                style={{
                  backgroundColor: NEO_BRUTALISM_THEME.buttonBg,
                  color: NEO_BRUTALISM_THEME.buttonText,
                  border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
                  boxShadow: NEO_BRUTALISM_THEME.buttonShadow,
                  fontFamily: neoBrutalism.typography.body.family,
                  borderRadius: neoBrutalism.borders.radius.none,
                  letterSpacing: neoBrutalism.typography.button.letterSpacing,
                  outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
                }}
              >
                Play Now
              </Link>
            </div>

            {/* Mobile Hamburger Button with 3px black border (Requirement 6.5) */}
            <button
              type="button"
              className="md:hidden flex items-center justify-center w-10 h-10 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
              onClick={toggleMobileMenu}
              aria-expanded={isMobileMenuOpen}
              aria-controls="mobile-nav-panel"
              aria-label={isMobileMenuOpen ? 'Close navigation menu' : 'Open navigation menu'}
              style={{
                border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
                backgroundColor: NEO_BRUTALISM_THEME.hamburgerBg,
                outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
              }}
            >
              <HamburgerIcon isOpen={isMobileMenuOpen} color={NEO_BRUTALISM_THEME.hamburgerIcon} />
            </button>
          </div>
        </div>
      </nav>

      {/* Spacer to prevent content from being hidden behind fixed nav */}
      <div className="h-16" aria-hidden="true" />

      {/* Mobile Slide-Out Panel */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <>
            {/* Backdrop overlay */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: PANEL_DURATION }}
              className="fixed inset-0 z-40 bg-black/60 md:hidden"
              onClick={() => setIsMobileMenuOpen(false)}
              aria-hidden="true"
            />

              {/* Slide-out panel with 4px black left border (Requirement 6.6) */}
            <motion.div
              id="mobile-nav-panel"
              role="dialog"
              aria-modal="true"
              aria-label="Navigation menu"
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ duration: PANEL_DURATION, ease: 'easeInOut' }}
              className="fixed top-0 right-0 bottom-0 z-50 w-[280px] max-w-[80vw] overflow-y-auto md:hidden"
              style={{
                backgroundColor: NEO_BRUTALISM_THEME.mobilePanelBg,
                borderLeft: `${neoBrutalism.borders.width.heavy} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
              }}
            >
              {/* Panel Header */}
              <div
                className="flex items-center justify-between p-4"
                style={{
                  borderBottom: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
                }}
              >
                <span
                  className="text-lg font-bold"
                  style={{
                    color: NEO_BRUTALISM_THEME.cyan,
                    fontFamily: neoBrutalism.typography.heading.family,
                    textShadow: NEO_BRUTALISM_THEME.logoGlow,
                  }}
                >
                  MENU
                </span>
                <button
                  type="button"
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="flex items-center justify-center w-8 h-8 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
                  aria-label="Close navigation menu"
                  style={{
                    border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
                    backgroundColor: NEO_BRUTALISM_THEME.navBg,
                    outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
                  }}
                >
                  <CloseIcon color={NEO_BRUTALISM_THEME.hamburgerIcon} />
                </button>
              </div>

              {/* Mobile Nav Links */}
              <div className="flex flex-col p-4 gap-1">
                {NAV_LINKS.map((link) => (
                  <MobileNavItem
                    key={link.href}
                    link={link}
                    isActive={isActive(link.href)}
                    onClick={() => setIsMobileMenuOpen(false)}
                  />
                ))}

                <div
                  className="my-3"
                  style={{
                    borderTop: `1px solid ${NEO_BRUTALISM_THEME.border}`,
                  }}
                  aria-hidden="true"
                />

                {AUTH_LINKS.map((link) => (
                  <MobileNavItem
                    key={link.href}
                    link={link}
                    isActive={isActive(link.href)}
                    onClick={() => setIsMobileMenuOpen(false)}
                  />
                ))}

                {/* Play Now CTA */}
                <Link
                  href="/play"
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="mt-3 px-4 py-3 font-bold text-center uppercase tracking-wide transition-all duration-150 active:translate-y-[1px] focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2"
                  style={{
                    backgroundColor: NEO_BRUTALISM_THEME.buttonBg,
                    color: NEO_BRUTALISM_THEME.buttonText,
                    border: `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.borderBlack}`,
                    boxShadow: NEO_BRUTALISM_THEME.buttonShadow,
                    fontFamily: neoBrutalism.typography.body.family,
                    borderRadius: neoBrutalism.borders.radius.none,
                    letterSpacing: neoBrutalism.typography.button.letterSpacing,
                    outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
                  }}
                >
                  Play Now
                </Link>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </>
  );
}

/** Desktop navigation link item with 14px bold text and cyan hover (Requirement 6.3) */
function NavItem({
  link,
  isActive: active,
}: {
  link: NavLink;
  isActive: boolean;
}) {
  return (
    <Link
      href={link.href}
      className="group relative px-3 py-2 text-sm font-medium transition-colors duration-150 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
      style={{
        color: active ? NEO_BRUTALISM_THEME.linkActive : NEO_BRUTALISM_THEME.linkInactive,
        fontFamily: neoBrutalism.typography.body.family,
        fontWeight: neoBrutalism.typography.body.weightBold,
        fontSize: neoBrutalism.typography.button.size,
        outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
      }}
      aria-current={active ? 'page' : undefined}
      onMouseEnter={(e) => {
        if (!active) {
          (e.currentTarget as HTMLElement).style.color = NEO_BRUTALISM_THEME.linkHover;
        }
      }}
      onMouseLeave={(e) => {
        if (!active) {
          (e.currentTarget as HTMLElement).style.color = NEO_BRUTALISM_THEME.linkInactive;
        }
      }}
    >
      {link.label}
      {/* 2px cyan accent line on active page (Requirement 6.1) */}
      {active && (
        <span
          className="absolute bottom-0 left-3 right-3"
          style={{
            height: NEO_BRUTALISM_THEME.accentLineHeight,
            backgroundColor: NEO_BRUTALISM_THEME.cyan,
          }}
          aria-hidden="true"
        />
      )}
    </Link>
  );
}

/** Mobile navigation link item with keyboard focus indicators (Requirement 6.8) */
function MobileNavItem({
  link,
  isActive: active,
  onClick,
}: {
  link: NavLink;
  isActive: boolean;
  onClick: () => void;
}) {
  return (
    <Link
      href={link.href}
      onClick={onClick}
      className="px-4 py-3 text-base font-medium transition-colors duration-150 focus:outline-none focus-visible:outline-2 focus-visible:outline-offset-2 rounded-sm"
      style={{
        color: active ? NEO_BRUTALISM_THEME.linkActive : NEO_BRUTALISM_THEME.linkInactive,
        backgroundColor: active ? 'rgba(0, 229, 255, 0.08)' : 'transparent',
        borderLeft: active
          ? `${neoBrutalism.borders.width.default} solid ${NEO_BRUTALISM_THEME.cyan}`
          : `${neoBrutalism.borders.width.default} solid transparent`,
        fontFamily: neoBrutalism.typography.body.family,
        fontWeight: neoBrutalism.typography.body.weightBold,
        outlineColor: NEO_BRUTALISM_THEME.focusRingColor,
      }}
      aria-current={active ? 'page' : undefined}
    >
      {link.label}
    </Link>
  );
}

