/** Hamburger/Close icon with animated state */
function HamburgerIcon({ isOpen, color }: { isOpen: boolean; color: string }) {
  return (
    <svg
      width="20"
      height="20"
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path
        d={isOpen ? 'M4 4L16 16' : 'M3 5H17'}
        stroke={color}
        strokeWidth="2"
        strokeLinecap="round"
        className="transition-all duration-200"
      />
      <path
        d={isOpen ? '' : 'M3 10H17'}
        stroke={isOpen ? 'transparent' : color}
        strokeWidth="2"
        strokeLinecap="round"
        className="transition-all duration-200"
      />
      <path
        d={isOpen ? 'M4 16L16 4' : 'M3 15H17'}
        stroke={color}
        strokeWidth="2"
        strokeLinecap="round"
        className="transition-all duration-200"
      />
    </svg>
  );
}

/** Close icon for mobile panel */
function CloseIcon({ color }: { color: string }) {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 16 16"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path
        d="M3 3L13 13M3 13L13 3"
        stroke={color}
        strokeWidth="2"
        strokeLinecap="round"
      />
    </svg>
  );
}

